<?php
namespace App\Models;
use App\Models\Concerns\BelongsToTenant;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;
class LoanRepaymentInstallment extends Model{use BelongsToTenant,HasUlids;protected $fillable=['cooperative_id','loan_id','installment_number','due_date','principal_due_minor','interest_due_minor','charges_due_minor','amount_paid_minor','principal_paid_minor','interest_paid_minor','charges_paid_minor','penalties_due_minor','penalties_paid_minor','recovery_expenses_due_minor','recovery_expenses_paid_minor','overdue_since','status'];protected function casts():array{return ['due_date'=>'date','principal_due_minor'=>'integer','interest_due_minor'=>'integer','charges_due_minor'=>'integer','amount_paid_minor'=>'integer','principal_paid_minor'=>'integer','interest_paid_minor'=>'integer','charges_paid_minor'=>'integer','penalties_due_minor'=>'integer','penalties_paid_minor'=>'integer','recovery_expenses_due_minor'=>'integer','recovery_expenses_paid_minor'=>'integer','overdue_since'=>'date','status'=>\App\Enums\InstallmentStatus::class];}public function loan():\Illuminate\Database\Eloquent\Relations\BelongsTo{return $this->belongsTo(Loan::class);}public function allocations():\Illuminate\Database\Eloquent\Relations\HasMany{return $this->hasMany(LoanRepaymentAllocation::class);}}
